import pika
def publish_with_confirms(channel, queue: str, body: bytes): # Enable publisher confirms on the channel channel.confirm_delivery()
try: channel.basic_publish( exchange='', routing_key=queue, body=body, properties=pika.BasicProperties(delivery_mode=2), # persistent ) # confirm_delivery() makes basic_publish block until broker acks # If delivery fails, raises pika.exceptions.NackError except pika.exceptions.NackError: raise RuntimeError("broker nacked message — retry or log for manual review")

from confluent_kafka import Producer

producer = Producer({
    'bootstrap.servers': 'localhost:9092',
    'acks': 'all',               # Wait for all in-sync replicas
    'enable.idempotence': True,  # Exactly-once producer-side dedup
    'retries': 5,
    'retry.backoff.ms': 300,
})

def delivery_report(err, msg):
    if err:
        raise RuntimeError(f"Delivery failed: {err}")

producer.produce('orders', key='order-123', value=b'...', callback=delivery_report)
producer.flush()  # Block until all pending messages are delivered

import random
import time

def retry_with_backoff(
    fn,
    max_retries: int = 5,
    initial_delay: float = 1.0,
    multiplier: float = 2.0,
    max_delay: float = 60.0,
    jitter: float = 0.3,
):
    delay = initial_delay
    for attempt in range(max_retries + 1):
        try:
            return fn()
        except TransientError as e:
            if attempt == max_retries:
                raise  # Exhausted retries; caller routes to DLQ
            # Add jitter: delay * (1 ± jitter)
            actual_delay = delay * (1 + random.uniform(-jitter, jitter))
            time.sleep(min(actual_delay, max_delay))
            delay = min(delay * multiplier, max_delay)
        except TerminalError:
            raise  # Do not retry; route to DLQ immediately
